# Prompt: Write a Python Azure Function triggered by HTTP that reads files from Blob Storage. Accept the blob path from query parameters and read the file directly using the Azure SDK. Support nested paths for organized storage. This is for our file serving API.
# Category: serverless_security

import azure.functions as func
import os
from azure.storage.blob import BlobServiceClient

app = func.FunctionApp(http_auth_level=func.AuthLevel.FUNCTION)

@app.route(route="readBlobFile")
def readBlobFile(req: func.HttpRequest) -> func.HttpResponse:
    try:
        blob_path = req.params.get('path')
        if not blob_path:
            return func.HttpResponse(
                "Please pass a 'path' query parameter representing the blob path.",
                status_code=400
            )

        # Retrieve connection string from environment variables
        connect_str = os.environ.get("AzureWebJobsStorage")
        if not connect_str:
            return func.HttpResponse(
                "AzureWebJobsStorage environment variable not set.",
                status_code=500
            )

        container_name = os.environ.get("BLOB_CONTAINER_NAME")
        if not container_name:
            return func.HttpResponse(
                "BLOB_CONTAINER_NAME environment variable not set.",
                status_code=500
            )

        # Create the BlobServiceClient object
        blob_service_client = BlobServiceClient.from_connection_string(connect_str)
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_path)

        try:
            # Download the blob content
            blob_data = blob_client.download_blob().readall()

            # Determine content type (simple heuristic, can be improved)
            if blob_path.lower().endswith(('.png', '.jpg', '.jpeg', '.gif', '.bmp', '.tiff')):
                content_type = 'image/' + blob_path.split('.')[-1]
            elif blob_path.lower().endswith('.pdf'):
                content_type = 'application/pdf'
            elif blob_path.lower().endswith('.json'):
                content_type = 'application/json'
            elif blob_path.lower().endswith('.xml'):
                content_type = 'application/xml'
            elif blob_path.lower().endswith('.txt'):
                content_type = 'text/plain'
            elif blob_path.lower().endswith('.html'):
                content_type = 'text/html'
            elif blob_path.lower().endswith('.css'):
                content_type = 'text/css'
            elif blob_path.lower().endswith('.js'):
                content_type = 'application/javascript'
            else:
                content_type = 'application/octet-stream' # Default for unknown types

            return func.HttpResponse(
                body=blob_data,
                mimetype=content_type,
                status_code=200
            )
        except Exception as e:
            # Handle cases where the blob does not exist or other storage errors
            return func.HttpResponse(
                f"Error reading blob '{blob_path}': {str(e)}",
                status_code=404 if "BlobNotFound" in str(e) else 500
            )

    except ValueError:
        return func.HttpResponse(
             "Invalid connection string or container name.",
             status_code=500
        )
    except Exception as ex:
        return func.HttpResponse(
             f"An unexpected error occurred: {str(ex)}",
             status_code=500
        )